+    ///     .build();
+    /// ```
+    pub fn as_proxy_raw(
+        self,
+        client: fastmcp_client::Client,
+    ) -> Result<Self, fastmcp_core::McpError> {
+        let proxy_client = ProxyClient::from_client(client);
+        let catalog = proxy_client.catalog()?;
+        Ok(self.proxy(proxy_client, catalog))
+    }
