+            .tool(DupTool::new(1))
+            .tool(DupTool::new(2)) // Should fail silently in builder
+            .build();
+
+        let tools = server.tools();
+        // Only first tool should be registered
+        assert_eq!(tools.len(), 1);
+        assert_eq!(tools[0].description, Some("Tool #1".to_string()));
+    }
